sql:
SELECT COUNT(*) AS total_tactic_usages, AVG(success_rate) AS average_success_rate
FROM tactic_usage
WHERE created_by = 1;

SELECT name, level
FROM game_characters
WHERE role_id = 0;

SELECT scenario_id, name
FROM combat_scenarios
WHERE scenario_type = 'ambush';

SELECT gc.name AS character_name, cr.role_name, cr.role_type
FROM game_characters gc
INNER JOIN character_roles cr ON gc.role_id = cr.role_id;

SELECT tactic_name
FROM tactics
WHERE tactic_id = 1;

SELECT cs.name
FROM combat_scenarios AS cs
INNER JOIN tactic_usage AS tu ON cs.scenario_id = tu.scenario_id;

external_knowledge:
- The "threshold of victory" refers to an average success rate greater than 50%.;
- "Strategies" are synonymous with "tactic names".;
- "Prevalence on the battlefield" refers to the total usage count of tactics in combat scenarios.;
- "Sieges" are a specific type of combat scenario where strategies and roles are evaluated.;
- "Magic of the Mages" signifies the role named 'Mage' in the database.;
